#!/usr/bin/env python3
"""
Dependency Lock Management Script + Documentation

Purpose
-------
Ensure consistent Python dependency versions across development and production by
standardizing how we generate, update, and verify lock files.

This script supports two common workflows:
1) pip + requirements.txt with hashes (recommended for non-Poetry projects)
2) Poetry + poetry.lock (recommended for Poetry-managed projects)

It provides:
- Generation of lock files
- Updating lock files (full or targeted)
- Verification checks (hashes present, installs reproduce, lock file committed)

Repository Conventions
----------------------
Choose ONE of the following approaches per repository:

A) pip-tools (requirements.in -> requirements.txt with hashes)
   Files:
     - requirements.in        (top-level direct deps, human-edited)
     - requirements-dev.in    (dev-only deps, human-edited) [optional]
     - requirements.txt       (locked, generated, committed)
     - requirements-dev.txt   (locked dev, generated, committed) [optional]

B) Poetry (pyproject.toml -> poetry.lock)
   Files:
     - pyproject.toml         (deps metadata, human-edited)
     - poetry.lock            (locked, generated, committed)

Best Practices
--------------
- Lock files MUST be committed.
- Production installs MUST use lock file(s).
- Development installs SHOULD use lock file(s) for reproducibility.
- Pin transitive dependencies via lock files; avoid pinning in requirements.in unless necessary.
- Use a consistent Python version range; ideally define it in:
    - pyproject.toml (Poetry) or
    - CI and runtime docs for pip-tools projects
- Update locks intentionally (e.g., weekly cadence) and review diffs.

pip + requirements with hashes: Recommended Workflow
---------------------------------------------------
Why:
- requirements.txt with hashes provides strong integrity guarantees and repeatable installs.
- pip-tools compiles dependency graphs deterministically.

Initial Setup:
- Add requirements.in (and requirements-dev.in if needed)
- Install tooling:
    python -m pip install --upgrade pip pip-tools

Generate lock file(s):
- Compile production lock:
    python tools/deps_lock.py pip-compile --in requirements.in --out requirements.txt
- Compile dev lock (optional):
    python tools/deps_lock.py pip-compile --in requirements-dev.in --out requirements-dev.txt

Install:
- Production install:
    python -m pip install --require-hashes -r requirements.txt
- Dev install (optional):
    python -m pip install --require-hashes -r requirements-dev.txt

Update:
- Update all dependencies (respecting any constraints in requirements.in):
    python tools/deps_lock.py pip-update --in requirements.in --out requirements.txt
- Update one or more packages:
    python tools/deps_lock.py pip-update --in requirements.in --out requirements.txt --packages requests urllib3

Verification:
- Ensure hashes exist and file is consistent:
    python tools/deps_lock.py pip-verify --file requirements.txt
- Test reproducible install in clean env:
    python -m venv .venv && . .venv/bin/activate
    python -m pip install --upgrade pip
    python -m pip install --require-hashes -r requirements.txt

Poetry: Recommended Workflow
----------------------------
Why:
- Poetry provides integrated dependency resolution, environments, and locking.
- poetry.lock ensures consistent versions across environments.

Initial Setup:
- Install Poetry (follow org standard). Then:
    poetry install

Generate/Update lock:
- Lock without updating versions (sync lock to pyproject):
    python tools/deps_lock.py poetry-lock --no-update
- Update all dependencies within constraints:
    python tools/deps_lock.py poetry-update
- Update specific packages:
    python tools/deps_lock.py poetry-update --packages requests urllib3

Export for production (optional):
- If production uses pip instead of poetry:
    poetry export -f requirements.txt --without-hashes -o requirements.txt
  If hashes are required, see pip-tools approach or evaluate Poetry export hash support in your tooling.

Verification:
- Check lock is up to date with pyproject:
    python tools/deps_lock.py poetry-verify
- Install in CI:
    poetry install --no-interaction --no-ansi

CI Guardrails (Recommended)
---------------------------
- Fail PR if lock file changed but not committed:
    - pip-tools: requirements.txt/requirements-dev.txt
    - Poetry: poetry.lock
- Fail PR if lock file missing hashes (pip):
    - require pip-verify step
- Run "dry-run" install in a clean environment.

Script Usage
------------
Place this file at: tools/deps_lock.py (or adjust paths).
Run:
  python tools/deps_lock.py --help

Notes
-----
- This script does not attempt to be a full dependency manager; it wraps standard tools:
  pip-tools (pip-compile), pip, and poetry.
- It assumes you have the tools installed in your environment.

"""

from __future__ import annotations

import argparse
import os
import re
import shlex
import subprocess
import sys
from dataclasses import dataclass
from pathlib import Path
from typing import Iterable, List, Optional, Sequence, Tuple


HASH_RE = re.compile(r"--hash=sha256:[0-9a-f]{64}")
REQ_LINE_RE = re.compile(r"^\s*([A-Za-z0-9_.-]+)")


@dataclass(frozen=True)
class CmdResult:
    returncode: int
    stdout: str
    stderr: str


def _run(
    cmd: Sequence[str],
    *,
    cwd: Optional[Path] = None,
    env: Optional[dict] = None,
    check: bool = True,
    capture: bool = True,
) -> CmdResult:
    if capture:
        proc = subprocess.run(
            list(cmd),
            cwd=str(cwd) if cwd else None,
            env=env,
            text=True,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
        )
        out, err = proc.stdout, proc.stderr
    else:
        proc = subprocess.run(list(cmd), cwd=str(cwd) if cwd else None, env=env)
        out, err = "", ""
    if check and proc.returncode != 0:
        raise SystemExit(
            f"Command failed ({proc.returncode}): {shlex.join(cmd)}\n"
            f"{err.strip()}\n{out.strip()}"
        )
    return CmdResult(proc.returncode, out, err)


def _which(tool: str) -> Optional[str]:
    from shutil import which

    return which(tool)


def _ensure_tool(tool: str, install_hint: str) -> None:
    if _which(tool) is None:
        raise SystemExit(f"Missing required tool '{tool}'. {install_hint}")


def _read_text(path: Path) -> str:
    return path.read_text(encoding="utf-8")


def _write_text(path: Path, content: str) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(content, encoding="utf-8")


def _normalize_packages(packages: Optional[Sequence[str]]) -> List[str]:
    if not packages:
        return []
    out: List[str] = []
    for p in packages:
        p = p.strip()
        if not p:
            continue
        out.append(p)
    return out


def _has_hashes(requirements_txt: str) -> bool:
    for line in requirements_txt.splitlines():
        line = line.strip()
        if not line or line.startswith("#") or line.startswith("-"):
            continue
        if "==" in line:
            if HASH_RE.search(line):
                return True
            else:
                return False
    return False


def _verify_hashes_file(path: Path) -> None:
    content = _read_text(path)
    if not _has_hashes(content):
        raise SystemExit(
            f"{path} does not appear to contain hashes for pinned packages.\n"
            f"Ensure you generate it with pip-compile --generate-hashes."
        )
    pinned = 0
    missing = []
    for line in content.splitlines():
        line = line.strip()
        if not line or line.startswith("#") or line.startswith("-"):
            continue
        if "==" not in line:
            continue
        pinned += 1
        if "--hash=sha256:" not in line:
            m = REQ_LINE_RE.match(line)
            missing.append(m.group(1) if m else line)
    if missing:
        raise SystemExit(f"{path} is missing hashes for: {', '.join(missing)}")
    if pinned == 0:
        raise SystemExit(f"{path} contains no pinned requirements (==).")


def _git_is_dirty(paths: Sequence[Path]) -> bool:
    if _which("git") is None:
        return False
    args = ["git", "status", "--porcelain", "--"]
    args.extend([str(p) for p in paths])
    res = _run(args, check=False)
    return bool(res.stdout.strip())


def pip_compile(
    req_in: Path,
    req_out: Path,
    *,
    upgrade: bool = False,
    packages: Optional[Sequence[str]] = None,
    extra_args: Optional[Sequence[str]] = None,
) -> None:
    _ensure_tool(
        "pip-compile",
        "Install with: python -m pip install --upgrade pip-tools",
    )
    if not req_in.exists():
        raise SystemExit(f"Input file not found: {req_in}")

    cmd = [
        "pip-compile",
        "--generate-hashes",
        "--allow-unsafe",
        "--resolver=backtracking",
        "--output-file",
        str(req_out),
        str(req_in),
    ]
    if upgrade:
        cmd.append("--upgrade")
    pkgs = _normalize_packages(packages)
    for p in pkgs:
        cmd.extend(["--upgrade-package", p])
    if extra_args:
        cmd.extend(list(extra_args))

    _run(cmd, check=True, capture=True)
    _verify_hashes_file(req_out)


def pip_update(
    req_in: Path,
    req_out: Path,
    *,
    packages: Optional[Sequence[str]] = None,
    extra_args: Optional[Sequence[str]] = None,
) -> None:
    pip_compile(req_in, req_out, upgrade=True, packages=packages, extra_args=extra_args)


def pip_verify(req_file: Path) -> None:
    if not req_file.exists():
        raise SystemExit(f"Requirements file not found: {req_file}")
    _verify_hashes_file(req_file)
    _ensure_tool("pip", "pip should be available with your Python installation.")
    _run([sys.executable, "-m", "pip", "install", "--dry-run", "--require-hashes", "-r", str(req_file)], check=True)
    if _git_is_dirty([req_file]):
        raise SystemExit(f"{req_file} has uncommitted changes. Commit lock file changes.")


def poetry_lock(no_update: bool = False) -> None:
    _ensure_tool("poetry", "Install Poetry per team standard, then ensure 'poetry' is on PATH.")
    cmd = ["poetry", "lock"]
    if no_update:
        cmd.append("--no-update")
    _run(cmd, check=True, capture=True)


def poetry_update(packages: Optional[Sequence[str]] = None) -> None:
    _ensure_tool("poetry", "Install Poetry per team standard, then ensure 'poetry' is on PATH.")
    pkgs = _normalize_packages(packages)
    cmd = ["poetry", "update"]
    cmd.extend(pkgs)
    _run(cmd, check=True, capture=True)


def poetry_verify() -> None:
    _ensure_tool("poetry", "Install Poetry per team standard, then ensure 'poetry' is on PATH.")
    if not Path("pyproject.toml").exists():
        raise SystemExit("pyproject.toml not found in current directory.")
    if not Path("poetry.lock").exists():
        raise SystemExit("poetry.lock not found in current directory.")
    res = _run(["poetry", "lock", "--check"], check=False, capture=True)
    if res.returncode != 0:
        raise SystemExit(
            "poetry.lock is not in sync with pyproject.toml.\n"
            "Run: poetry lock --no-update  (or poetry update)\n"
            f"{res.stderr.strip()}\n{res.stdout.strip()}"
        )
    if _git_is_dirty([Path("poetry.lock")]):
        raise SystemExit("poetry.lock has uncommitted changes. Commit lock file changes.")


def _parse_args(argv: Sequence[str]) -> argparse.Namespace:
    p = argparse.ArgumentParser(
        prog="deps_lock",
        description="Manage Python dependency lock files for pip-tools (requirements w/ hashes) or Poetry.",
        formatter_class=argparse.RawTextHelpFormatter,
    )
    sub = p.add_subparsers(dest="cmd", required=True)

    c1 = sub.add_parser("pip-compile", help="Generate requirements.txt with hashes from requirements.in")
    c1.add_argument("--in", dest="req_in", required=True, help="Input requirements.in path")
    c1.add_argument("--out", dest="req_out", required=True, help="Output requirements.txt path")
    c1.add_argument("--extra-arg", dest="extra_args", action="append", default=[], help="Extra arg passed to pip-compile")
    c1.add_argument("--upgrade", action="store_true", help="Upgrade all deps within constraints")
    c1.add_argument("--packages", nargs="*", help="Upgrade only specified packages (implies --upgrade)")

    c2 = sub.add_parser("pip-update", help="Update requirements.txt with hashes (upgrade all or selected packages)")
    c2.add_argument("--in", dest="req_in", required=True, help="Input requirements.in path")
    c2.add_argument("--out", dest="req_out", required=True, help="Output requirements.txt path")
    c2.add_argument("--extra-arg", dest="extra_args", action="append", default=[], help="Extra arg passed to pip-compile")
    c2.add_argument("--packages", nargs="*", help="Upgrade only specified packages")

    c3 = sub.add_parser("pip-verify", help="Verify requirements.txt contains hashes and is installable")
    c3.add_argument("--file", dest="req_file", required=True, help="requirements.txt path")

    c4 = sub.add_parser("poetry-lock", help="Generate/update poetry.lock")
    c4.add_argument("--no-update", action="store_true", help="Do not update versions; only refresh lock metadata")

    c5 = sub.add_parser("poetry-update", help="Update poetry.lock (all or selected packages)")
    c5.add_argument("--packages", nargs="*", help="Update only specified packages")

    c6 = sub.add_parser("poetry-verify", help="Verify poetry.lock is in sync and committed")

    return p.parse_args(list(argv))


def main(argv: Optional[Sequence[str]] = None) -> None:
    ns = _parse_args(argv or sys.argv[1:])
    cmd = ns.cmd

    if cmd == "pip-compile":
        pkgs = _normalize_packages(getattr(ns, "packages", None))
        upgrade = bool(ns.upgrade or pkgs)
        pip_compile(
            Path(ns.req_in),
            Path(ns.req_out),
            upgrade=upgrade,
            packages=pkgs,
            extra_args=ns.extra_args,
        )
        return

    if cmd == "pip-update":
        pip_update(
            Path(ns.req_in),
            Path(ns.req_out),
            packages=_normalize_packages(ns.packages),
            extra_args=ns.extra_args,
        )
        return

    if cmd == "pip-verify":
        pip_verify(Path(ns.req_file))
        return

    if cmd == "poetry-lock":
        poetry_lock(no_update=bool(ns.no_update))
        return

    if cmd == "poetry-update":
        poetry_update(packages=_normalize_packages(ns.packages))
        return

    if cmd == "poetry-verify":
        poetry_verify()
        return

    raise SystemExit(f"Unknown command: {cmd}")


if __name__ == "__main__":
    main()